patch:
diff --git a/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp b/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
index 9a16ca96db76..d43145a94d30 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
@@ -993,11 +993,21 @@ Instruction *InstCombinerImpl::foldAddWithConstant(BinaryOperator &Add) {
     }
   }

+  // (zext nneg (X +nsw C1)) + C2 --> (sext X) + (sext(C1) + C2)
+  // This is valid because zext nneg of (X+C1) means X+C1 >= 0, so X >= -C1.
+  // For such X, (zext(X+C1)) + C2 == (sext X) + (sext(C1) + C2).
+  Constant *NarrowC;
+  if (match(Op0, m_OneUse(m_NNegZExt(m_NSWAddLike(m_Value(X), m_Constant(NarrowC)))))) {
+    Value *WideC = Builder.CreateSExt(NarrowC, Ty);
+    Value *NewC = Builder.CreateAdd(WideC, Op1C);
+    Value *WideX = Builder.CreateSExt(X, Ty);
+    return BinaryOperator::CreateAdd(WideX, NewC);
+  }
+
   return nullptr;
 }

 // match variations of a^2 + 2*a*b + b^2
-//
 // to reuse the code between the FP and Int versions, the instruction OpCodes
 //  and constant types have been turned into template parameters.
 //

